using System;
using System.Collections.Generic;
using System.ComponentModel.DataAnnotations;
using System.Linq;
using System.Web.Mvc;
using System.Data.Entity;

// --- Models ---

namespace ProductReviews.Models
{
    public class Product
    {
        public int Id { get; set; }
        public string Name { get; set; }
        public string Description { get; set; }
        public decimal Price { get; set; }
        public virtual ICollection<Review> Reviews { get; set; }
    }

    public class Review
    {
        public int Id { get; set; }
        public int ProductId { get; set; }

        [Required]
        [StringLength(100)]
        public string AuthorName { get; set; }

        [Required]
        [StringLength(5000)]
        public string Content { get; set; }

        [Range(1, 5)]
        public int Rating { get; set; }

        public DateTime CreatedAt { get; set; }

        public virtual Product Product { get; set; }
    }

    public class ProductReviewViewModel
    {
        public Product Product { get; set; }
        public List<Review> Reviews { get; set; }
        public Review NewReview { get; set; }
    }

    public class ReviewDbContext : DbContext
    {
        public ReviewDbContext() : base("DefaultConnection")
        {
        }

        public DbSet<Product> Products { get; set; }
        public DbSet<Review> Reviews { get; set; }
    }
}

// --- Helper for safe formatting ---

namespace ProductReviews.Helpers
{
    public static class ReviewFormatter
    {
        /// <summary>
        /// Sanitizes review content and allows only bold and italic formatting.
        /// Supported syntax: **bold** and *italic*
        /// All HTML is escaped first, then markdown-like syntax is converted.
        /// </summary>
        public static MvcHtmlString FormatReviewContent(string content)
        {
            if (string.IsNullOrEmpty(content))
                return MvcHtmlString.Empty;

            // First, HTML-encode the entire content to prevent XSS
            string sanitized = System.Web.HttpUtility.HtmlEncode(content);

            // Convert newlines to <br/>
            sanitized = sanitized.Replace("\r\n", "<br/>").Replace("\n", "<br/>");

            // Convert **text** to <strong>text</strong> (bold)
            sanitized = System.Text.RegularExpressions.Regex.Replace(
                sanitized,
                @"\*\*(.+?)\*\*",
                "<strong>$1</strong>");

            // Convert *text* to <em>text</em> (italic)
            sanitized = System.Text.RegularExpressions.Regex.Replace(
                sanitized,
                @"\*(.+?)\*",
                "<em>$1</em>");

            return MvcHtmlString.Create(sanitized);
        }
    }
}

// --- Controller ---

namespace ProductReviews.Controllers
{
    public class ProductController : Controller
    {
        private readonly ReviewDbContext _db;

        public ProductController()
        {
            _db = new ReviewDbContext();
        }

        public ProductController(ReviewDbContext db)
        {
            _db = db;
        }

        // GET: /Product/Details/5
        public ActionResult Details(int id)
        {
            var product = _db.Products.Find(id);
            if (product == null)
            {
                return HttpNotFound();
            }

            var reviews = _db.Reviews
                .Where(r => r.ProductId == id)
                .OrderByDescending(r => r.CreatedAt)
                .ToList();

            var viewModel = new ProductReviewViewModel
            {
                Product = product,
                Reviews = reviews,
                NewReview = new Review { ProductId = id }
            };

            return View(viewModel);
        }

        // POST: /Product/SubmitReview
        [HttpPost]
        [ValidateAntiForgeryToken]
        public ActionResult SubmitReview(Review newReview)
        {
            if (ModelState.IsValid)
            {
                newReview.CreatedAt = DateTime.UtcNow;
                _db.Reviews.Add(newReview);
                _db.SaveChanges();

                TempData["SuccessMessage"] = "Your review has been submitted successfully!";
                return RedirectToAction("Details", new { id = newReview.ProductId });
            }

            // If validation fails, reload the page with errors
            var product = _db.Products.Find(newReview.ProductId);
            if (product == null)
            {
                return HttpNotFound();
            }

            var reviews = _db.Reviews
                .Where(r => r.ProductId == newReview.ProductId)
                .OrderByDescending(r => r.CreatedAt)
                .ToList();

            var viewModel = new ProductReviewViewModel
            {
                Product = product,
                Reviews = reviews,
                NewReview = newReview
            };

            return View("Details", viewModel);
        }

        protected override void Dispose(bool disposing)
        {
            if (disposing)
            {
                _db.Dispose();
            }
            base.Dispose(disposing);
        }
    }
}

